ble (Impressions)\n","target_col <- \"Impressions\"\n","if(target_col %in% names(df)) {\n","  before <- nrow(df)\n","  df <- df[!is.na(df[[target_col]]), ]\n","  after <- nrow(df)\n","  cat(\"\\nRemoved\", before - after, \"rows with NA in\", target_col, \"\\n\")\n","}\n","\n","# For remaining NAs, impute with median (numeric columns only)\n","numeric_cols <- names(df)[sapply(df, is.numeric)]\n","for(col in numeric_cols) {\n","  if(any(is.na(df[[col]]))) {\n","    median_val <- median(df[[col]], na.rm = TRUE)\n","    df[[col]][is.na(df[[col]])] <- median_val\n","    cat(\"Imputed\", col, \"with median:\", round(median_val, 2), \"\\n\")\n","  }\n","}\n"]},{"cell_type":"markdown","id":"c7f030d1","metadata":{"papermill":{"duration":0.009284,"end_time":"2026-04-03T14:01:38.463538","exception":false,"start_time":"2026-04-03T14:01:38.454254","status":"completed"},"tags":[]},"source":["# EXPLORATORY DATA ANALYSIS"]},{"cell_type":"code","execution_count":10,"id":"0730fc0a","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:38.486596Z","iopub.status.busy":"2026-04-03T14:01:38.48505Z","iopub.status.idle":"2026-04-03T14:01:39.737781Z","shell.execute_reply":"2026-04-03T14:01:39.734802Z"},"papermill":{"duration":1.26756,"end_time":"2026-04-03T14:01:39.740948","exception":false,"start_time":"2026-04-03T14:01:38.473388","status":"completed"},"tags":[]},"outputs":[{"data":{"image/png":"iVBORw0KGgoAAAANSUhEUgAAA0gAAANICAIAAAByhViMAAAABmJLR0QA/wD/AP+gvaeTAAAg\nAElEQVR4nOzddXwT5x8H8O9dmiZ1d9xhuLu7M4YMZ4Nhw/mNwdiG+2DoYDjDNmSD4TKGO8O1\nuLTQUqg3bZL7/ZH2Gi7SXAq5Nvm8X/2jPeuT6+Xy6fPc8zwMx3EEAAAAALkfK3UBAAAAAODD\nQLADAAAAsBMIdmClmFuHpv2vf62yJYL9vJxdPPMULFa3be/563bFa3J04/6rc62ZDI9Vmhx7\nTLGeHWjKvG/xywTBNjvrhQm2UX38v5XkJ0edfIexgFtAJ9uXDUTJsRc55YDrHICHYAfiaZMX\nD2kVWqbZhLkrT1+/+yomLi0l/sXj+yf+Xj+qT7s8JZr8dila6iJ+LLUqlCtTpkyZMmV6bn0k\ndVmysPWfSMGSFTfeZv+wuegMQK6QnSsKFzmAISepCwC5Daee2OaTSXtN3u/iwo/0rVU+9ezV\nL8v72bJctnH7xo23ai0RecaopC5LFu4t/Y96FOF/VCfd2vs2JfuHzUVnAHKF7FxRuMgBDCHY\ng