,"                                   \"\\nMedian:\", round(median(df$Impressions), 0)),\n","           hjust = 0, vjust = 1.5, size = 3.5)\n","\n","# Traffic source distribution comparison\n","traffic_cols <- c(\"From.Home\", \"From.Hashtags\", \"From.Explore\", \"From.Other\")\n","traffic_long <- df %>%\n","  select(all_of(traffic_cols)) %>%\n","  pivot_longer(everything(), names_to = \"Source\", values_to = \"Impressions\")\n","\n","p2 <- ggplot(traffic_long, aes(x = Source, y = Impressions, fill = Source)) +\n","  geom_boxplot() +\n","  scale_y_log10() +\n","  labs(title = \"Impressions by Traffic Source\",\n","       x = \"Traffic Source\", y = \"Impressions (log10)\") +\n","  theme_minimal() +\n","  theme(legend.position = \"none\") +\n","  coord_flip()\n","\n","# Engagement metrics correlation heatmap\n","engagement_cols <- c(\"Likes\", \"Shares\", \"Comments\", \"Saves\", \"Profile.Visits\", \"Impressions\")\n","cor_matrix <- cor(df[engagement_cols], use = \"complete.obs\")\n","\n","p3 <- corrplot(cor_matrix, method = \"color\", type = \"upper\", \n","               order = \"hclust\", tl.col = \"black\", tl.srt = 45,\n","               title = \"Correlation Matrix - Engagement Metrics\", \n","               mar = c(0, 0, 1, 0))\n","\n","# Display plots\n","print(p1)\n","print(p2)\n","print(p3)\n","\n","# Summary statistics of key metrics\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"KEY METRICS SUMMARY\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\\n\")\n","\n","summary_stats <- df %>%\n","  summarise(\n","    Total_Impressions = sum(Impressions),\n","    Avg_Impressions = mean(Impressions),\n","    Median_Impressions = median(Impressions),\n","    Max_Impressions = max(Impressions),\n","    Avg_Likes = mean(Likes),\n","    Avg_Comments = mean(Comments),\n","    Avg_Shares = mean(Shares),\n","    Avg_Saves = mean(Saves),\n","    Engagement_Rate = mean((Likes + Comments + Shares + Saves) / Impressions * 100, na.rm = TRUE)\n","  )\n","\n","print(summary_stats)\n","\n","# Traffic source contribution\n","traffic_contribution <- df %>%\n","  summarise(\n","    Home_Pct = mean(From.Home / Impressions * 100, na.rm = TRUE),\n","    Hashtags_Pct = mean(From.Hashtags / Impressions * 100, na.rm = TRUE),\n","    Explore_Pct = mean(From.Explore / Impressions * 100, na.rm = TRUE),\n","    Other_Pct = mean(From.Other / Impressions * 100, na.rm = TRUE)\n","  ) %>%\n","  pivot_longer(everything(), names_to = \"Source\", values_to = \"Percentage\")\n","\n","cat(\"\\nAverage Traffic Source Contribution:\\n\")\n","print(traffic_contribution)\n"]},{"cell_type":"markdown","id":"f6f533bb","metadata":{"papermill":{"duration":0.023363,"end_time":"2026-04-03T14:01:39.780509","exception":false,"start_time":"2026-04-03T14:01:39.757146","status":"completed"},"tags":[]},"source":["# FEATURE ENGINEERING "]},{"cell_type":"code","execution_count":11,"id":"09261017","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:39.824698Z","iopub.status.busy":"2026-04-03T14:01:39.821854Z","iopub.status.idle":"2026-04-03T14:01:39.863413Z","shell.execute_reply":"2026-04-03T14:01:39.861508Z"},"papermill":{"duration":0.065259,"end_time":"2026-04-03T14:01:39.865961","exception":false,"start_time":"2026-04-03T14:01:39.800702","status":"completed"},"tags":[]},"outputs":[],"source":["# Create derived features\n","df_engineered <- df %>%\n","  mutate(\n","    # Engagement metrics\n","    Total_Engagement = Likes + Comments + Shares + Saves,\n","    Engagement_Rate = Total_Engagement / Impressions * 100,\n","    \n","    # Traffic ratios\n","    Home_Ratio = From.Home / Impressions,\n","    Hashtags_Ratio = From.Hashtags / Impressions,\n","    Explore_Ratio = From.Explore / Impressions,\n","    \n","    # Interaction features\n","    Like_to_Save_Ratio = ifelse(Saves > 0, Likes / Saves, Likes),\n","    Comment_to_Like_Ratio = ifelse(Likes > 0, Comments / Likes, 0),\n","    Share_to_Save_Ratio = ifelse(Saves > 0, Shares / Saves, 0),\n","    \n","    # Viral potential (shares + saves relative to impressions)\n","    Viral_Score = (Shares + Saves) / Impressions * 100,\n","    \n","    # Engagement quality (weighted by action importance)\n","    Weighted_Engagement = Likes * 1 + Comments * 3 + Shares * 5 + Saves * 4,\n","    \n","    # Traffic diversity (entropy-like measure)\n","    Traffic_Diversity = ifelse(Impressions > 0,\n","      -((From.Home/Impressions) * log((From.Home/Impressions) + 0.001) +\n","        (From.Hashtags/Impressions) * log((From.Hashtags/Impressions) + 0.001) +\n","        (From.Explore/Impressions) * log((From.Explore/Impressions) + 0.001) +\n","        (From.Other/Impressions) * log((From.Other/Impressions) + 0.001)), 0)\n","  )\n","\n","# Handle infinite/NaN values from log operations\n","df_engineered <- df_engineered %>%\n","  mutate(across(where(is.numeric), ~ ifelse(is.infinite(.) | is.nan(.), 0, .)))"]},{"cell_type":"markdown","id":"0bfd593d","metadata":{"papermill":{"duration":0.012282,"end_time":"2026-04-03T14:01:39.890909","exception":false,"start_time":"2026-04-03T14:01:39.878627","status":"completed"},"tags":[]},"source":["# TRAIN-TEST SPLIT "]},{"cell_type":"code","execution_count":12,"id":"ce971587","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:39.920029Z","iopub.status.busy":"2026-04-03T14:01:39.918424Z","iopub.status.idle":"2026-04-03T14:01:39.964933Z","shell.execute_reply":"2026-04-03T14:01:39.96299Z"},"papermill":{"duration":0.064166,"end_time":"2026-04-03T14:01:39.967529","exception":false,"start_time":"2026-04-03T14:01:39.903363","status":"completed"},"tags":[]},"outputs":[{"name":"stdout","output_type":"stream","text":["\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\