x_depth eta gamma colsample_bytree min_child_weight subsample\n","9     100         7 0.1     0              0.8                1       0.8\n"]},{"name":"stdout","output_type":"stream","text":["XGBoost RMSE (CV): 1683.42 \n"]}],"source":["# Setup cross-validation\n","train_control <- trainControl(\n","  method = \"cv\",\n","  number = 5,\n","  verboseIter = FALSE,\n","  savePredictions = \"final\"\n",")\n","\n","# 7.1 Linear Regression (Baseline)\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"TRAINING LINEAR REGRESSION (BASELINE)\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","\n","set.seed(42)\n","model_lm <- train(\n","  x = X_train,\n","  y = y_train,\n","  method = \"lm\",\n","  trControl = train_control\n",")\n","cat(\"Linear Regression RMSE (CV):\", round(min(model_lm$results$RMSE), 2), \"\\n\")\n","\n","# 7.2 Ridge Regression (L2 Regularization)\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"TRAINING RIDGE REGRESSION\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","\n","set.seed(42)\n","ridge_grid <- expand.grid(alpha = 0, lambda = seq(0.001, 1, length = 20))\n","model_ridge <- train(\n","  x = X_train,\n","  y = y_train,\n","  method = \"glmnet\",\n","  tuneGrid = ridge_grid,\n","  trControl = train_control\n",")\n","cat(\"Best lambda:\", round(model_ridge$bestTune$lambda, 4), \"\\n\")\n","cat(\"Ridge RMSE (CV):\", round(min(model_ridge$results$RMSE), 2), \"\\n\")\n","\n","# 7.3 Lasso Regression (L1 Regularization - Feature Selection)\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"TRAINING LASSO REGRESSION\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","\n","set.seed(42)\n","lasso_grid <- expand.grid(alpha = 1, lambda = seq(0.001, 1, length = 20))\n","model_lasso <- train(\n","  x = X_train,\n","  y = y_train,\n","  method = \"glmnet\",\n","  tuneGrid = lasso_grid,\n","  trControl = train_control\n",")\n","cat(\"Best lambda:\", round(model_lasso$bestTune$lambda, 4), \"\\n\")\n","cat(\"Lasso RMSE (CV):\", round(min(model_lasso$results$RMSE), 2), \"\\n\")\n","\n","# 7.4 Random Forest\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"TRAINING RANDOM FOREST\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","\n","set.seed(42)\n","rf_grid <- expand.grid(mtry = c(3, 5, 7, 9, 11))\n","model_rf <- train(\n","  x = X_train,\n","  y = y_train,\n","  method = \"rf\",\n","  tuneGrid = rf_grid,\n","  trControl = train_control,\n","  ntree = 500,\n","  importance = TRUE\n",")\n","cat(\"Best mtry:\", model_rf$bestTune$mtry, \"\\n\")\n","cat(\"Random Forest RMSE (CV):\", round(min(model_rf$results$RMSE), 2), \"\\n\")\n","\n","# 7.5 XGBoost\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"TRAINING XGBOOST\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","\n","set.seed(42)\n","xgb_grid <- expand.grid(\n","  nrounds = 100,\n","  max_depth = c(3, 5, 7),\n","  eta = c(0.01, 0.05, 0.1),\n","  gamma = 0,\n","  colsample_bytree = 0.8,\n","  min_child_weight = 1,\n","  subsample = 0.8\n",")\n","\n","model_xgb <- train(\n","  x = as.matrix(X_train),\n","  y = y_train,\n","  method = \"xgbTree\",\n","  tuneGrid = xgb_grid,\n","  trControl = train_control,\n","  verbosity = 0\n",")\n","cat(\"Best parameters:\\n\")\n","print(model_xgb$bestTune)\n","cat(\"XGBoost RMSE (CV):\", round(min(model_xgb$results$RMSE), 2), \"\\n\")\n"]},{"cell_type":"markdown","id":"12c11c95","metadata":{"papermill":{"duration":0.014563,"end_time":"2026-04-03T14:01:47.160146","exception":false,"start_time":"2026-04-03T14:01:47.145583","status":"completed"},"tags":[]},"source":["# MODEL EVALUATION ON TEST SET"]},{"cell_type":"code","execution_count":14,"id":"4c1ba0c6","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:47.191707Z","iopub.status.busy":"2026-04-03T14:01:47.190114Z","iopub.status.idle":"2026-04-03T14:01:47.257369Z","sh