pressions))\n","cat(sprintf(\"  - Average Saves: %.1f\\n\", insights$Avg_Saves_per_1K_Impressions))\n","cat(sprintf(\"  - Average Shares: %.1f\\n\", insights$Avg_Shares_per_1K_Impressions))\n","\n","cat(\"\\nTRAFFIC SOURCE EFFECTIVENESS:\\n\")\n","cat(sprintf(\"  - Home Feed: %.1f%% of impressions\\n\", insights$Home_Efficiency * 100))\n","cat(sprintf(\"  - Hashtags: %.1f%% of impressions\\n\", insights$Hashtag_Efficiency * 100))\n","cat(sprintf(\"  - Explore: %.1f%% of impressions\\n\", insights$Explore_Efficiency * 100))\n","\n","# Optimal thresholds based on top-performing posts\n","top_posts <- df_engineered %>%\n","  arrange(desc(Impressions)) %>%\n","  head(10)\n","\n","cat(\"\\nCHARACTERISTICS OF TOP 10 PERFORMING POSTS:\\n\")\n","cat(sprintf(\"  - Avg Likes: %.0f\\n\", mean(top_posts$Likes)))\n","cat(sprintf(\"  - Avg Comments: %.0f\\n\", mean(top_posts$Comments)))\n","cat(sprintf(\"  - Avg Saves: %.0f\\n\", mean(top_posts$Saves)))\n","cat(sprintf(\"  - Avg Shares: %.0f\\n\", mean(top_posts$Shares)))\n","cat(sprintf(\"  - Hashtag Contribution: %.1f%%\\n\", mean(top_posts$Hashtags_Ratio * 100)))\n","cat(sprintf(\"  - Explore Contribution: %.1f%%\\n\", mean(top_posts$Explore_Ratio * 100)))\n"]},{"cell_type":"markdown","id":"b7fe5fad","metadata":{"papermill":{"duration":0.020023,"end_time":"2026-04-03T14:01:48.396483","exception":false,"start_time":"2026-04-03T14:01:48.37646","status":"completed"},"tags":[]},"source":["# PREDICTION FUNCTION FOR NEW POSTS"]},{"cell_type":"code","execution_count":18,"id":"b742750f","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:48.437778Z","iopub.status.busy":"2026-04-03T14:01:48.43621Z","iopub.status.idle":"2026-04-03T14:01:48.516036Z","shell.execute_reply":"2026-04-03T14:01:48.513969Z"},"papermill":{"duration":0.103336,"end_time":"2026-04-03T14:01:48.51893","exception":false,"start_time":"2026-04-03T14:01:48.415594","status":"completed"},"tags":[]},"outputs":[{"name":"stdout","output_type":"stream","text":["\n