   Comments = comments,\n","    Shares = shares,\n","    Saves = saves,\n","    Profile.Visits = profile_visits,\n","    From.Home = from_home,\n","    From.Hashtags = from_hashtags,\n","    From.Explore = from_explore,\n","    From.Other = from_other,\n","    Total_Engagement = total_engagement,\n","    Home_Ratio = from_home / total_impressions_input,\n","    Hashtags_Ratio = from_hashtags / total_impressions_input,\n","    Explore_Ratio = from_explore / total_impressions_input,\n","    Viral_Score = (shares + saves) / total_impressions_input * 100,\n","    Weighted_Engagement = likes * 1 + comments * 3 + shares * 5 + saves * 4\n","  )\n","  \n","  # Make prediction (assuming 'model_rf' is the trained model)\n","  prediction <- predict(model_lm, new_post)\n","  \n","  return(round(prediction, 0))\n","}\n","\n","# Example prediction\n","example_post <- predict_impressions(\n","  likes = 500, comments = 50, shares = 20, saves = 100,\n","  profile_visits = 200, from_home = 2000, from_hashtags = 1500,\n","  from_explore = 800, from_other = 200\n",")\n","\n","cat(\"\\n\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"EXAMPLE PREDICTION\\n\")\n","cat(\"=\" %>% rep(70) %>% paste(collapse=\"\"), \"\\n\")\n","cat(\"Sample post with:\\n\")\n","cat(\"  - 500 likes, 50 comments, 20 shares, 100 saves\\n\")\n","cat(\"  - 200 profile visits\\n\")\n","cat(\"  - Traffic: Home=2000, Hashtags=1500, Explore=800, Other=200\\n\")\n","cat(sprintf(\"\\nPredicted Total Impressions: %s\\n\", format(example_post, big.mark = \",\")))"]},{"cell_type":"markdown","id":"4eebfa0e","metadata":{"papermill":{"duration":0.018971,"end_time":"2026-04-03T14:01:48.557128","exception":false,"start_time":"2026-04-03T14:01:48.538157","status":"completed"},"tags":[]},"source":["# SAVE MODEL FOR PRODUCTION"]},{"cell_type":"code","execution_count":19,"id":"369f29f9","metadata":{"execution":{"iopub.execute_input":"2026-04-03T14:01:48.598797Z","iopub.status.busy":"2026-04-03T14:01:48.597264Z","iopub.st